/**
 * purify.min.js - Minimal HTML sanitizer
 * Strips all HTML tags except safe ones: p, br, strong, em, a, ul, ol, li,
 * code, pre, h1-h6, blockquote, img, table, th, tr, td, span, div, hr, del, sup, sub
 * Removes event handlers and javascript: links
 */
(function() {
  'use strict';

  var SAFE_TAGS = {
    p: true, br: true, strong: true, em: true, a: true,
    ul: true, ol: true, li: true, code: true, pre: true,
    h1: true, h2: true, h3: true, h4: true, h5: true, h6: true,
    blockquote: true, img: true, table: true, th: true, tr: true, td: true,
    span: true, div: true, hr: true, del: true, sup: true, sub: true,
    u: true, s: true, mark: true, small: true, ins: true,
    b: true, i: true, tt: true
  };

  var SAFE_ATTRS = {
    a: ['href', 'title', 'target', 'rel'],
    img: ['src', 'alt', 'title', 'width', 'height', 'loading'],
    td: ['colspan', 'rowspan', 'align'],
    th: ['colspan', 'rowspan', 'align'],
    table: ['border', 'cellpadding', 'cellspacing'],
    tr: ['align'],
    code: ['class'],
    pre: ['class'],
    span: ['class'],
    div: ['class'],
    p: ['class'],
    h1: ['class'], h2: ['class'], h3: ['class'], h4: ['class'], h5: ['class'], h6: ['class'],
    a: ['href', 'title', 'target', 'rel', 'class']
  };

  function purify(dirty) {
    if (typeof dirty !== 'string') return '';
    
    // Remove script tags and their content
    dirty = dirty.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '');
    dirty = dirty.replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, '');
    
    // Remove event handlers (on* attributes)
    dirty = dirty.replace(/\s+on\w+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]+)/gi, '');
    
    // Remove javascript: protocol in links
    dirty = dirty.replace(/href\s*=\s*(?:"javascript:[^"]*"|'javascript:[^']*')/gi, 'href="#');
    
    // Parse and rebuild HTML
    var parser = new DOMParser();
    var doc;
    try {
      doc = parser.parseFromString('<div id="purify-root">' + dirty + '</div>', 'text/html');
    } catch(e) {
      return dirty.replace(/<[^>]*>/g, '');
    }

    function sanitizeNode(node) {
      var result = '';
      
      for (var i = 0; i < node.childNodes.length; i++) {
        var child = node.childNodes[i];
        
        if (child.nodeType === 3) { // Text node
          result += child.textContent;
        } else if (child.nodeType === 1) { // Element node
          var tagName = child.tagName.toLowerCase();
          
          if (SAFE_TAGS[tagName]) {
            result += '<' + tagName;
            
            // Safe attributes
            var allowed = SAFE_ATTRS[tagName] || [];
            for (var j = 0; j < child.attributes.length; j++) {
              var attr = child.attributes[j];
              var attrName = attr.name.toLowerCase();
              if (allowed.indexOf(attrName) !== -1 && attrName.indexOf('on') !== 0) {
                result += ' ' + attr.name + '="' + attr.value.replace(/"/g, '&quot;') + '"';
              }
            }
            
            result += '>';
            result += sanitizeNode(child);
            result += '</' + tagName + '>';
          } else {
            // Strip tag but keep content
            result += sanitizeNode(child);
          }
        }
        // Comments and other node types are stripped
      }
      
      return result;
    }

    var root = doc.getElementById('purify-root') || doc.body;
    return sanitizeNode(root);
  }

  function sanitize(dirty, config) {
    return purify(dirty);
  }

  // DOMPurify-like API
  var DOMPurify = {
    sanitize: sanitize,
    setConfig: function() {},
    clearConfig: function() {},
    isValidAttribute: function() { return true; },
    removed: [],
    isSupported: true
  };

  if (typeof module !== 'undefined' && module.exports) {
    module.exports = DOMPurify;
    module.exports.sanitize = sanitize;
  } else {
    window.DOMPurify = DOMPurify;
  }
})();
